+    // Clock regressions are warnings — the report should still pass
+    assert!(report.passed);
+    assert_eq!(
+        report.count_by_severity(ViolationSeverity::Warning),
+        1
+    );
+    assert_eq!(report.count_by_kind(ViolationKind::ClockRegression), 1);
+}
